const now = new Date();
const fmt = (value) => value.toISOString().slice(0, 10);
const out = [];

for (const item of items) {
  const row = item.json;
  const secid = row.secid;
  if (!secid || row.active === false || row.active === 'false') continue;

  const engine = row.engine || 'stock';
  const market = row.market || 'shares';
  const board = row.board || 'TQBR';
  const defaultDaysBack = Number(row.default_days_back || 1);
  const overlapDays = Number(row.overlap_days || 0);

  const tillDate = new Date(now);
  const defaultFromDate = new Date(now);
  defaultFromDate.setUTCDate(defaultFromDate.getUTCDate() - defaultDaysBack);

  let fromDate = new Date(defaultFromDate);
  let cursorLoaded = null;
  let requestMode = 'bootstrap';

  if (row.cursor_value) {
    const parsedCursor = new Date(row.cursor_value);
    if (!Number.isNaN(parsedCursor.getTime())) {
      cursorLoaded = parsedCursor.toISOString();
      const candidateFromDate = new Date(parsedCursor);
      candidateFromDate.setUTCDate(candidateFromDate.getUTCDate() - overlapDays);
      if (candidateFromDate > fromDate) {
        fromDate = candidateFromDate;
      }
      requestMode = 'incremental';
    }
  }

  if (fromDate > tillDate) {
    fromDate = new Date(tillDate);
  }

  const candleUrl = `https://iss.moex.com/iss/engines/${engine}/markets/${market}/boards/${board}/securities/${secid}/candles.json?interval=${row.interval_code}&from=${fmt(fromDate)}&till=${fmt(tillDate)}`;

  out.push({
    json: {
      ...row,
      engine,
      market,
      board,
      from_date: fmt(fromDate),
      till_date: fmt(tillDate),
      cursor_loaded: cursorLoaded,
      request_mode: requestMode,
      candle_url: candleUrl,
    },
  });
}

return out;

const computeHash = (value) => {
  const input = String(value || '');
  let hash = 0;
  for (let index = 0; index < input.length; index++) {
    hash = ((hash << 5) - hash) + input.charCodeAt(index);
    hash |= 0;
  }
  return `h${(hash >>> 0).toString(16)}`;
};
const results = [];

for (const item of items) {
  const payload = item.json;
  const candleBlock = payload.candles || {};
  const columns = candleBlock.columns || [];
  const rows = candleBlock.data || [];
  const candles = rows.map((row) => {
    const entry = {};
    columns.forEach((column, index) => {
      entry[column] = row[index];
    });
    return entry;
  });

  if (candles.length === 0) continue;

  const normalizedCandles = candles
    .map((entry) => {
      const candleTime = entry.begin || entry.end || null;
      return {
        candle_time: candleTime ? new Date(candleTime).toISOString() : null,
        begin_at: entry.begin ? new Date(entry.begin).toISOString() : null,
        end_at: entry.end ? new Date(entry.end).toISOString() : null,
        open: entry.open ?? null,
        high: entry.high ?? null,
        low: entry.low ?? null,
        close: entry.close ?? null,
        volume: entry.volume ?? null,
        value: entry.value ?? null,
        payload: entry,
      };
    })
    .filter((entry) => entry.candle_time);

  if (normalizedCandles.length === 0) continue;

  const last = candles[candles.length - 1] || {};
  const prev = candles[candles.length - 2] || {};
  const latestClose = Number(last.close ?? 0);
  const prevClose = Number(prev.close ?? last.open ?? 0);
  const changePct = prevClose ? Number((((latestClose - prevClose) / prevClose) * 100).toFixed(4)) : 0;
  const recentCandles = normalizedCandles.slice(-5);
  const latestCandleTime = normalizedCandles[normalizedCandles.length - 1].candle_time;

  const summaryText = [
    `Инструмент: ${payload.secid}`,
    `Эмитент: ${payload.issuer_name || payload.secid}`,
    `Группа: ${payload.instrument_group || 'stocks'}`,
    `Интервал: ${payload.interval_name}`,
    `Режим сбора: ${payload.request_mode}`,
    `Период выгрузки: ${payload.from_date} - ${payload.till_date}`,
    `Предыдущий cursor: ${payload.cursor_loaded || 'none'}`,
    `Количество свечей: ${normalizedCandles.length}`,
    `Последняя свеча: ${latestCandleTime}`,
    `Последнее закрытие: ${latestClose || 'n/a'}`,
    `Изменение к предыдущей свече: ${changePct}%`,
    `Последний объем: ${last.volume ?? 'n/a'}`,
    `OHLC последней свечи: O=${last.open ?? 'n/a'} H=${last.high ?? 'n/a'} L=${last.low ?? 'n/a'} C=${last.close ?? 'n/a'}`,
    `Последние 5 свечей JSON: ${JSON.stringify(recentCandles)}`,
  ].join('\n');

  const sourceKey = `moex/candles/${payload.secid}/${payload.interval_name}/${latestCandleTime}`;
  const payloadObject = {
    secid: payload.secid,
    issuer_name: payload.issuer_name,
    interval_name: payload.interval_name,
    interval_code: payload.interval_code,
    request_mode: payload.request_mode,
    cursor_key: payload.cursor_key,
    cursor_loaded: payload.cursor_loaded,
    from_date: payload.from_date,
    till_date: payload.till_date,
    latest_candle_time: latestCandleTime,
    latest_close: latestClose,
    change_pct: changePct,
    last_volume: Number(last.volume ?? 0),
    recent_candles: recentCandles,
  };
  const payloadJson = JSON.stringify(payloadObject);
  const documentHash = computeHash(summaryText);

  results.push({
    json: {
      secid: payload.secid,
      engine: payload.engine,
      board: payload.board,
      market: payload.market,
      instrument_group: payload.instrument_group,
      issuer_name: payload.issuer_name,
      interval_code: payload.interval_code,
      interval_name: payload.interval_name,
      request_mode: payload.request_mode,
      cursor_key: payload.cursor_key,
      cursor_loaded: payload.cursor_loaded,
      from_date: payload.from_date,
      till_date: payload.till_date,
      latest_candle_time: latestCandleTime,
      candles_count: normalizedCandles.length,
      latest_close: latestClose,
      change_pct: changePct,
      last_volume: Number(last.volume ?? 0),
      summary_text: summaryText,
      knowledge_text: summaryText,
      source_key: sourceKey,
      document_hash: documentHash,
      payload_json: payloadJson,
      candles_json: JSON.stringify(normalizedCandles),
    },
  });
}

return results;
